import React from 'react';
import logoImg from '../assets/logo.png'; // change to .svg or .jpg if needed

export default function Logo({ size = 36, showText = true }) {
  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
      {/* Logo image */}
      <img
        src={logoImg}
        alt="TalentOS logo"
        style={{
          width: size,
          height: size,
          objectFit: 'contain',
          flexShrink: 0,
        }}
      />

      {/* Wordmark */}
      {showText && (
        <div>
          <div style={{ fontWeight: 700, fontSize: 15, letterSpacing: '-0.3px', lineHeight: 1.1 }}>
            <span style={{ color: '#ffffff' }}>Talent</span>
            <span style={{ color: '#93C5FD' }}>OS</span>
          </div>
          <div style={{ fontSize: 11, color: '#6B7280', letterSpacing: '0.08em', textTransform: 'uppercase', marginTop: 1 }}>
            Smart Recruitment
          </div>
        </div>
      )}
    </div>
  );
}

// Larger version for auth pages (Login / Register)
export function LogoLight({ size = 44 }) {
  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
      <img
        src={logoImg}
        alt="TalentOS logo"
        style={{ width: size, height: size, objectFit: 'contain' }}
      />
      <div>
        <div style={{ fontWeight: 700, fontSize: 20, letterSpacing: '-0.5px', lineHeight: 1.1 }}>
          <span style={{ color: '#111827' }}>Talent</span>
          <span style={{ color: '#1B4FD8' }}>OS</span>
        </div>
        <div style={{ fontSize: 12, color: '#6B7280', letterSpacing: '0.1em', textTransform: 'uppercase', marginTop: 2 }}>
          Smart Recruitment
        </div>
      </div>
    </div>
  );
}

// Icon only — no wordmark
export function LogoIcon({ size = 36 }) {
  return (
    <img
      src={logoImg}
      alt="TalentOS"
      style={{ width: size, height: size, objectFit: 'contain' }}
    />
  );
}
